package com.shecancode.user.controller; import com.shecancode.user.dto.AuthDtos.*; import com.shecancode.user.model.AppUser; import com.shecancode.user.repo.UserRepository; import org.springframework.http.*; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/api/auth") public class AuthController { private final UserRepository users; private final BCryptPasswordEncoder encoder; public AuthController(UserRepository u,BCryptPasswordEncoder e){users=u;encoder=e;} @PostMapping("/register") public ResponseEntity<?> register(@RequestBody RegisterRequest r){if(users.findByEmailIgnoreCase(r.email()).isPresent())return ResponseEntity.badRequest().body("Email already exists");AppUser u=new AppUser(r.firstName(),r.lastName(),r.email().toLowerCase(),encoder.encode(r.password()),"CUSTOMER");return ResponseEntity.status(201).body(users.save(u));} @PostMapping("/login") public ResponseEntity<?> login(@RequestBody LoginRequest r){AppUser u=users.findByEmailIgnoreCase(r.email()).orElse(null);if(u==null||!u.isEnabled()||!encoder.matches(r.password(),u.getPassword()))return ResponseEntity.status(401).body("Invalid credentials");return ResponseEntity.ok(new LoginResponse(u,"Login successful"));} }